-- RelayBoard synthetic analytics warehouse schema
-- All data is fictional, generated by scripts/generate_db.py for demo/eval only.

CREATE TABLE IF NOT EXISTS accounts (
    account_id     INTEGER PRIMARY KEY,
    company_name   TEXT NOT NULL,
    industry       TEXT NOT NULL,
    region         TEXT NOT NULL CHECK (region IN ('NA', 'EMEA', 'APAC', 'LATAM')),
    signup_date    TEXT NOT NULL,  -- ISO date YYYY-MM-DD
    segment        TEXT NOT NULL CHECK (segment IN ('smb', 'mid_market', 'enterprise'))
);

CREATE TABLE IF NOT EXISTS subscriptions (
    subscription_id INTEGER PRIMARY KEY,
    account_id      INTEGER NOT NULL REFERENCES accounts(account_id),
    plan_tier       TEXT NOT NULL CHECK (plan_tier IN ('starter', 'pro', 'enterprise')),
    mrr             REAL NOT NULL CHECK (mrr >= 0),
    start_date      TEXT NOT NULL,
    end_date        TEXT,  -- NULL = still active
    status          TEXT NOT NULL CHECK (status IN ('active', 'churned', 'paused'))
);

CREATE TABLE IF NOT EXISTS usage_daily (
    usage_id    INTEGER PRIMARY KEY,
    account_id  INTEGER NOT NULL REFERENCES accounts(account_id),
    usage_date  TEXT NOT NULL,
    metric      TEXT NOT NULL CHECK (metric IN ('api_calls', 'active_users', 'workflow_runs')),
    value       REAL NOT NULL CHECK (value >= 0)
);

CREATE TABLE IF NOT EXISTS support_tickets (
    ticket_id         INTEGER PRIMARY KEY,
    account_id        INTEGER NOT NULL REFERENCES accounts(account_id),
    created_at        TEXT NOT NULL,
    category          TEXT NOT NULL,
    severity          TEXT NOT NULL CHECK (severity IN ('low', 'medium', 'high', 'critical')),
    resolution_hours  REAL,
    sla_met           INTEGER NOT NULL CHECK (sla_met IN (0, 1))
);

CREATE TABLE IF NOT EXISTS plan_changes (
    change_id    INTEGER PRIMARY KEY,
    account_id   INTEGER NOT NULL REFERENCES accounts(account_id),
    change_date  TEXT NOT NULL,
    from_tier    TEXT NOT NULL,
    to_tier      TEXT NOT NULL,
    mrr_delta    REAL NOT NULL
);

CREATE INDEX IF NOT EXISTS idx_subscriptions_account ON subscriptions(account_id);
CREATE INDEX IF NOT EXISTS idx_subscriptions_dates ON subscriptions(start_date, end_date);
CREATE INDEX IF NOT EXISTS idx_usage_daily_account_date ON usage_daily(account_id, usage_date);
CREATE INDEX IF NOT EXISTS idx_support_tickets_account ON support_tickets(account_id);
CREATE INDEX IF NOT EXISTS idx_plan_changes_account ON plan_changes(account_id);
